import { MinPriorityQueue } from '@datastructures-js/priority-queue';

function solve(edges, online, k) {
    const n = online.length;
    const adj = new Array(n).fill().map(() => []);
    for (const [u, v, cost] of edges) {
        adj[u].push([v, cost]);
    }

    const maxHeap = new MaxPriorityQueue({ priority: (x) => x.minCost });
    maxHeap.enqueue({ node: 0, totalCost: 0, minCost: Infinity });

    while (!maxHeap.isEmpty()) {
        const { node, totalCost, minCost } = maxHeap.dequeue().element;
        if (node === n - 1) {
            return minCost === Infinity ? -1 : minCost;
        }
        for (const [neighbor, cost] of adj[node]) {
            if (!online[neighbor] && neighbor !== n - 1) {
                continue;
            }
            const newTotalCost = totalCost + cost;
            if (newTotalCost > k) {
                continue;
            }
            const newMinCost = Math.min(minCost, cost);
            maxHeap.enqueue({ node: neighbor, totalCost: newTotalCost, minCost: newMinCost });
        }
    }
    return -1;
}

