    constructor(options) {
        this.queue = new MinPriorityQueue({
            priority: (x) => -options.priority(x)
        });
    }
    enqueue(element) {
        this.queue.enqueue(element);
    }
    dequeue() {
        return this.queue.dequeue();
    }
    isEmpty() {
        return this.queue.isEmpty();
    }
}

